{"method_body":"{
  result := new int[inputs.Length];
  var n := inputs.Length;
  result[0] := inputs[n - 1];
  result[n - 1] := inputs[0];

  var i := 1;
  while i < n - 1
    invariant 1 <= i <= n - 1
    invariant result.Length == n
    invariant result[0] == inputs[n - 1]
    invariant result[n - 1] == inputs[0]
    invariant forall j :: 1 <= j < i ==> result[j] == inputs[j]
  {
    result[i] := inputs[i];
    i := i + 1;
  }
}"}
